from lxml import etree
import io

def process_soap_request(xml_content):
    # Enable DTD validation
    parser = etree.XMLParser(load_dtd=True, resolve_entities=True, no_network=False)
    
    try:
        # Parse the XML with DTD validation
        root = etree.fromstring(xml_content.encode('utf-8'), parser)
    except etree.XMLSyntaxError as e:
        raise ValueError(f"Invalid XML: {e}")
    
    # Find SOAP envelope
    soap_envelope = root.find('.//{http://schemas.xmlsoap.org/soap/envelope/}Envelope')
    if soap_envelope is None:
        raise ValueError("Invalid SOAP envelope")
    
    # Extract message body
    soap_body = soap_envelope.find('.//{http://schemas.xmlsoap.org/soap/envelope/}Body')
    if soap_body is None:
        raise ValueError("SOAP body not found")
    
    # Return the raw XML of the body content
    body_content = etree.tostring(soap_body, encoding='unicode', method='xml')
    
    # Extract the actual message content (remove SOAP body wrapper)
    message_start = body_content.find('>') + 1
    message_end = body_content.rfind('<')
    
    if message_start > 0 and message_end > message_start:
        message_content = body_content[message_start:message_end]
    else:
        message_content = body_content
    
    return message_content